@once
<style>
.account-main{background:#f5f7fb;min-height:100vh;padding-bottom:64px}.account-header{background:#fff;border-bottom:1px solid #e2e8f0}.account-container{width:min(1120px,calc(100% - 40px));margin:auto}.account-header .account-container{min-height:132px;display:flex;align-items:center;justify-content:space-between;gap:20px}.account-eyebrow{display:block;color:#2563eb;font-size:10px;font-weight:900;letter-spacing:.12em;text-transform:uppercase}.account-header h1{margin:7px 0 5px;color:#0f172a;font-size:28px;font-weight:850;letter-spacing:-.6px}.account-header p{margin:0;color:#64748b;font-size:12px}.account-body{padding-top:26px}.account-action{display:inline-flex;align-items:center;justify-content:center;gap:8px;padding:12px 16px;border-radius:10px;background:#2563eb;color:#fff!important;text-decoration:none;border:0;font-size:12px;font-weight:800;cursor:pointer}.account-action.secondary{background:#fff;color:#334155!important;border:1px solid #cbd5e1}.account-card{background:#fff;border:1px solid #e2e8f0;border-radius:16px;box-shadow:0 3px 14px rgba(15,23,42,.035);overflow:hidden}.account-card-head{padding:17px 20px;border-bottom:1px solid #edf2f7;display:flex;align-items:center;justify-content:space-between;gap:12px}.account-card-head h2{margin:0;color:#0f172a;font-size:15px;font-weight:850}.account-card-head p{margin:4px 0 0;color:#64748b;font-size:10px}.account-flash{padding:12px 14px;margin-bottom:16px;border-radius:10px;font-size:11px;font-weight:700}.account-flash.success{background:#ecfdf5;border:1px solid #a7f3d0;color:#047857}.account-flash.error{background:#fef2f2;border:1px solid #fecaca;color:#b91c1c}.account-empty{text-align:center;padding:55px 20px}.account-empty>span{width:58px;height:58px;border-radius:17px;background:#eff6ff;color:#2563eb;display:grid;place-items:center;margin:auto;font-size:21px}.account-empty h2{margin:15px 0 6px;color:#0f172a;font-size:17px}.account-empty p{max-width:410px;margin:0 auto 19px;color:#64748b;font-size:11px;line-height:1.65}@media(max-width:700px){.account-container{width:calc(100% - 24px)}.account-header .account-container{min-height:150px;align-items:flex-start;justify-content:center;flex-direction:column}.account-header h1{font-size:24px}.account-header .account-action{width:100%}.account-body{padding-top:16px}}
</style>
@endonce
